import{_ as t,o as a,c as i,a1 as s}from"./chunks/framework.DdbKPUhY.js";const f=JSON.parse('{"title":"Safety Inquiries","description":"","frontmatter":{"title":"Safety Inquiries","editLink":false,"lastUpdated":false},"headers":[],"relativePath":"safety.md","filePath":"safety.md"}'),r={name:"safety.md"};function o(n,e,l,d,h,u){return a(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="✦-safety-inquiries" tabindex="-1">✦ Safety Inquiries <a class="header-anchor" href="#✦-safety-inquiries" aria-label="Permalink to &quot;✦ Safety Inquiries&quot;">​</a></h1><h2 id="what-is-this-space" tabindex="-1">What is this space? <a class="header-anchor" href="#what-is-this-space" aria-label="Permalink to &quot;What is this space?&quot;">​</a></h2><p>This is a community-driven archive created to preserve a directory of editing resources once the original source goes offline. Because the future of the original links is uncertain, these files have been mirrored onto private backup links to ensure they remain accessible to editors who rely on them.</p><h2 id="credits-origin" tabindex="-1">Credits &amp; Origin <a class="header-anchor" href="#credits-origin" aria-label="Permalink to &quot;Credits &amp; Origin&quot;">​</a></h2><p>Please note that we are strictly <strong>reuploaders</strong>, not software developers or the creators of these packages. Just like the original founders at Satvrn, we do not modify, crack, or program these files. We are simply archiving a previously trusted and clean distribution hub so it isn&#39;t lost in time.</p><h2 id="future-updates" tabindex="-1">Future Updates <a class="header-anchor" href="#future-updates" aria-label="Permalink to &quot;Future Updates&quot;">​</a></h2><p>Because this is a static archive, <strong>these files will not be updated.</strong> We will not be uploading future versions of these tools or software patches. What is currently in the directory is all that will be available.</p><h2 id="user-responsibility-safety-read-before-downloading" tabindex="-1">User Responsibility &amp; Safety <span class="note2">(read before downloading)</span> <a class="header-anchor" href="#user-responsibility-safety-read-before-downloading" aria-label="Permalink to &quot;User Responsibility &amp; Safety &lt;span class=&quot;note2&quot;&gt;(read before downloading)&lt;/span&gt;&quot;">​</a></h2><p>While the original distribution hub has been widely recognized as a trustworthy, safe staple within the editing community for a long time, downloading and setting up modified software always carries inherent risks.</p><ul><li>You are entirely responsible for your own device’s security.</li><li>If you do not know how to safely manage file extractions, troubleshoot installation blocks, or do your own technical research, <strong>do not proceed.</strong> If you are uncomfortable taking these steps, you are highly encouraged to play it safe and officially purchase the services and software directly from the legitimate creators.</li></ul>',10)])])}const p=t(r,[["render",o]]);export{f as __pageData,p as default};
